/* Google OAuth 시작: GoTrue authorize 로 리다이렉트. 복귀 시 URL 해시에 세션 토큰이 담겨 돌아온다. */
function authGoogleStart() {
  if (!SB_ON) return;
  const redirect = window.location.origin + window.location.pathname;
  window.location.href = SB_URL + "/auth/v1/authorize?provider=google&redirect_to=" + encodeURIComponent(redirect);
}
/* OAuth 복귀 해시(access_token 있고 recovery 아님) 파싱 */
function parseOAuthHash() {
  try {
    const h = (typeof window !== "undefined" && window.location.hash) || "";
    if (h.indexOf("access_token") < 0 || h.indexOf("type=recovery") >= 0) return null;
    const p = new URLSearchParams(h.replace(/^#/, ""));
    const at = p.get("access_token"); if (!at) return null;
    return { access_token: at, refresh_token: p.get("refresh_token") || null };
  } catch { return null; }
}
/* OAuth 해시 → 세션 적용 + 계정 로드. username 이 비어 있으면(최초 구글 로그인) 아이디 설정 필요 */
async function authFromHash(h) {
  if (!SB_ON) return null;
  SB_TOKEN = h.access_token; saveRefresh(h.refresh_token || null);
  let uid = null;
  try { const r = await fetch(SB_URL + "/auth/v1/user", { headers: sbHeaders() }); if (r.ok) { const u = await r.json(); uid = (u && u.id) || null; } } catch { }
  if (!uid) { clearSession(); return null; }
  return await loadAccount(uid);
}
/* 최초 구글 로그인 후 아이디 확정 → profiles 행 생성(기존 username 체계 공유) */
async function claimUsername(uid, username) {
  if (!SB_ON || !uid) return { ok: false, error: "offline" };
  const uname = (username || "").toLowerCase();
  if (!ALNUM.test(uname) || uname.length < 3 || uname.length > 20) return { ok: false, error: "invalid" };
  // 서버측 원자적 확정: claim_username 은 auth.uid() 로 본인 행을 만들고, 타인이 쓰는 아이디면 'taken' 반환.
  // 동시성 레이스는 username UNIQUE 제약으로 차단. 예외/예상외 응답이면 진행하지 않음(fail-closed → 도용 불가).
  try {
    const res = await sbRpc("claim_username", { p_username: uname });
    const v = Array.isArray(res) ? res[0] : res;
    if (v === "ok" || v === "already") return { ok: true };
    if (v === "taken") return { ok: false, error: "username_taken" };
    if (v === "invalid") return { ok: false, error: "invalid" };
    return { ok: false, error: "failed" };
  } catch { return { ok: false, error: "failed" }; }
}

function UsernameSetupModal({ account, onDone, onCancel }) {
  const [id, setId] = useState(""); const [err, setErr] = useState(""); const [busy, setBusy] = useState(false);
  const submit = async () => {
    setErr("");
    if (!ALNUM.test(id) || id.length < 3 || id.length > 20) { setErr("아이디는 영문+숫자 3~20자여야 합니다."); return; }
    setBusy(true);
    try {
      const r = await claimUsername(account.uid, id);
      if (!r.ok) { setErr(r.error === "username_taken" ? "이미 사용 중인 아이디입니다." : r.error === "invalid" ? "아이디 형식이 올바르지 않습니다." : "처리 중 오류가 발생했습니다."); setBusy(false); return; }
      onDone({ uid: account.uid, username: id.toLowerCase(), pub: account.pub || {}, progress: account.progress || {} });
    } catch { setErr("처리 중 오류가 발생했습니다."); setBusy(false); }
  };
  const inputStyle = { width: "100%", padding: "10px 12px", borderRadius: 9, border: "1px solid #C9B58C", marginBottom: 8, background: "#fff", color: T.ink };
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.6)", zIndex: 90, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
      <div style={{ width: "100%", maxWidth: 340, background: "linear-gradient(180deg,#F2E8D5,#E2D2B2)", borderRadius: 16, padding: 20, border: "1px solid #CDB98E", boxShadow: "0 20px 50px -10px rgba(0,0,0,.7)" }}>
        <div className="flex items-center justify-between" style={{ marginBottom: 8 }}>
          <div style={{ fontSize: 17, fontWeight: 800, color: T.ink }}>아이디 설정</div>
          <button onClick={onCancel} className="press" style={{ width: 28, height: 28, borderRadius: 8, border: "none", background: "#0002", color: T.ink, cursor: "pointer" }}>✕</button>
        </div>
        <p style={{ fontSize: 12.5, color: T.inkSoft, lineHeight: 1.5, marginBottom: 12 }}>Google 계정으로 처음 로그인했어요. 친구 검색·프로필에 표시될 아이디를 정해 주세요.</p>
        <input value={id} onChange={(e) => setId(e.target.value)} placeholder="아이디 (영문+숫자 3~20자)" autoComplete="username" onKeyDown={(e) => e.key === "Enter" && submit()} style={inputStyle} />
        {err && <div style={{ fontSize: 12, color: T.blunder, marginBottom: 8 }}>{err}</div>}
        <button onClick={submit} disabled={busy} className="press" style={{ width: "100%", padding: "11px 0", borderRadius: 10, background: "linear-gradient(180deg,#3A2516,#241509)", color: T.ivoryHi, fontWeight: 800, border: "none", cursor: "pointer" }}>{busy ? "설정 중…" : "시작하기"}</button>
        <div style={{ textAlign: "center", marginTop: 8 }}><button onClick={onCancel} style={{ color: T.inkSoft, fontSize: 12, background: "none", border: "none", cursor: "pointer", textDecoration: "underline" }}>취소하고 로그아웃</button></div>
      </div>
    </div>
  );
}

function AuthModal({ onClose, onAuth, initialMode }) {
  const [mode, setMode] = useState(initialMode || "login");
  const [email, setEmail] = useState(""); const [id, setId] = useState(""); const [pw, setPw] = useState("");
  const [err, setErr] = useState(""); const [busy, setBusy] = useState(false); const [sent, setSent] = useState(false);
  const [pw2, setPw2] = useState(""); const [showPw, setShowPw] = useState(false); const [googleHint, setGoogleHint] = useState(false);
  const submit = async () => {
    setErr(""); setGoogleHint(false);
    if (mode === "reset") {
      const who = email.trim();
      if (!who) { setErr("아이디 또는 이메일을 입력하세요."); return; }
      setBusy(true);
      try { await authRecover(who); } catch { }
      setBusy(false); setSent(true);
      return;
    }
    const isEmail = email.includes("@");
    const em = email.trim();
    if (mode === "signup" && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(em)) { setErr("올바른 이메일을 입력하세요."); return; }
    if (mode === "login" && !em) { setErr("아이디 또는 이메일을 입력하세요."); return; }
    if (pw.length < 6) { setErr("비밀번호는 6자 이상이어야 합니다."); return; }
    if (mode === "signup") {
      if (!ALNUM.test(id) || id.length < 3 || id.length > 20) { setErr("아이디는 영문+숫자 3~20자여야 합니다."); return; }
      if (pw !== pw2) { setErr("비밀번호가 일치하지 않습니다."); return; }
    }
    setBusy(true);
    try {
      if (mode === "signup") {
        const r = await authSignup(em, pw, id);
        if (!r || !r.ok) {
          if (r && r.error === "email_taken") {
            const provs = await accountProviders(em);
            if (provs.indexOf("google") >= 0 && provs.indexOf("email") < 0) { setGoogleHint(true); setErr("이 이메일은 Google 계정으로 가입되어 있어요. 아래 ‘Google로 계속하기’로 로그인하세요."); setBusy(false); return; }
            setErr("이미 가입된 이메일입니다. 로그인해 주세요."); setBusy(false); return;
          }
          setErr(r && r.error === "username_taken" ? "이미 사용 중인 아이디입니다."
            : r && r.error === "confirm_required" ? "확인 메일을 보냈습니다. 인증 후 로그인하세요."
            : r && r.error === "offline" ? "서버 연결이 필요합니다."
            : "가입 처리 중 오류가 발생했습니다.");
          setBusy(false); return;
        }
        onAuth(r.account);
      } else {
        const r = await authLogin(em, pw);
        if (!r || !r.ok) {
          if (r && r.error === "offline") { setErr("서버 연결이 필요합니다."); setBusy(false); return; }
          const probe = (r && r.email) || (isEmail ? em : "");
          if (probe) { const provs = await accountProviders(probe); if (provs.indexOf("google") >= 0 && provs.indexOf("email") < 0) { setGoogleHint(true); setErr("이 계정은 Google로 가입되어 있어요. 아래 ‘Google로 계속하기’로 로그인하세요."); setBusy(false); return; } }
          setErr("아이디/이메일 또는 비밀번호가 올바르지 않습니다."); setBusy(false); return;
        }
        onAuth(r.account);
      }
    } catch { setErr("처리 중 오류가 발생했습니다."); }
    setBusy(false);
  };
  const inputStyle = { width: "100%", padding: "10px 12px", borderRadius: 9, border: "1px solid #C9B58C", marginBottom: 8, background: "#fff", color: T.ink };
  const title = mode === "login" ? "다시 오신 걸 환영해요" : mode === "signup" ? "OpenChess 시작하기" : "비밀번호 찾기";
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.6)", zIndex: 80, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
      <div onClick={(e) => e.stopPropagation()} style={{ position: "relative", width: "100%", maxWidth: 340, background: "linear-gradient(180deg,#F2E8D5,#E2D2B2)", borderRadius: 16, padding: 20, border: "1px solid #CDB98E", boxShadow: "0 20px 50px -10px rgba(0,0,0,.7)" }}>
        {/* (UI6) 창 닫기 버튼은 항상 블록 우상단 고정 */}
        <button onClick={onClose} className="press" style={{ position: "absolute", top: 12, right: 12, zIndex: 10, width: 28, height: 28, borderRadius: 8, border: "none", background: "#0002", color: T.ink, cursor: "pointer" }}>✕</button>
        <div style={{ display: "flex", justifyContent: "center", alignItems: "flex-end", gap: 2, marginBottom: 6, marginTop: -4 }}>
          <Mascot name="milku" emotion={mode === "login" ? "wink" : mode === "signup" ? "great" : "surprise"} size={92} />
          <Mascot name="kokoa" emotion={mode === "signup" ? "celebrate" : "happy"} size={92} />
        </div>
        <div style={{ marginBottom: 14, paddingRight: 30 }}>
          <div style={{ fontSize: 17, fontWeight: 800, color: T.ink }}>{title}</div>
        </div>
        {mode === "reset" ? (sent ? (
          <>
            <p style={{ fontSize: 13, color: T.ink, lineHeight: 1.6, marginBottom: 14 }}>입력하신 계정이 존재하면 연동된 이메일로 비밀번호 재설정 링크를 보냈습니다. 메일함(스팸함 포함)을 확인해 주세요.</p>
            <button onClick={() => { setMode("login"); setSent(false); setErr(""); setPw(""); }} className="press" style={{ width: "100%", padding: "11px 0", borderRadius: 10, background: "linear-gradient(180deg,#3A2516,#241509)", color: T.ivoryHi, fontWeight: 800, border: "none", cursor: "pointer" }}>로그인으로 돌아가기</button>
          </>
        ) : (
          <>
            <p style={{ fontSize: 12, color: T.inkSoft, lineHeight: 1.5, marginBottom: 10 }}>가입 시 사용한 아이디 또는 이메일을 입력하면 연동된 이메일로 재설정 링크를 보내드립니다.</p>
            <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="아이디 또는 이메일" autoComplete="username" onKeyDown={(e) => e.key === "Enter" && submit()} style={inputStyle} />
            {err && <div style={{ fontSize: 12, color: T.blunder, marginBottom: 8 }}>{err}</div>}
            <button onClick={submit} disabled={busy} className="press" style={{ width: "100%", padding: "11px 0", borderRadius: 10, background: "linear-gradient(180deg,#3A2516,#241509)", color: T.ivoryHi, fontWeight: 800, border: "none", cursor: "pointer", marginBottom: 10 }}>{busy ? "보내는 중…" : "재설정 메일 보내기"}</button>
            <div style={{ textAlign: "center", fontSize: 12.5, color: T.inkSoft }}>
              <button onClick={() => { setMode("login"); setErr(""); }} style={{ color: "#5A3A22", fontWeight: 800, background: "none", border: "none", cursor: "pointer", textDecoration: "underline" }}>로그인으로 돌아가기</button>
            </div>
          </>
        )) : (
          <>
            <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder={mode === "login" ? "아이디 또는 이메일" : "이메일"} type={mode === "login" ? "text" : "email"} autoComplete={mode === "login" ? "username" : "email"} onKeyDown={(e) => e.key === "Enter" && submit()} style={inputStyle} />
            {mode === "signup" && <input value={id} onChange={(e) => setId(e.target.value)} placeholder="아이디 (영문+숫자 3~20자, 공개 표시)" style={inputStyle} />}
            <div style={{ position: "relative" }}>
              <input type={showPw ? "text" : "password"} value={pw} onChange={(e) => setPw(e.target.value)} placeholder="비밀번호 (6자 이상)" autoComplete={mode === "login" ? "current-password" : "new-password"} onKeyDown={(e) => e.key === "Enter" && submit()} style={{ ...inputStyle, paddingRight: 40 }} />
              <button type="button" onClick={() => setShowPw((v) => !v)} aria-label={showPw ? "비밀번호 숨기기" : "비밀번호 보이기"} title={showPw ? "비밀번호 숨기기" : "비밀번호 보이기"} style={{ position: "absolute", right: 6, top: 5, width: 30, height: 30, display: "flex", alignItems: "center", justifyContent: "center", background: "none", border: "none", cursor: "pointer", color: T.inkSoft }}>{showPw ? <EyeOff size={17} /> : <Eye size={17} />}</button>
            </div>
            {mode === "signup" && <input type={showPw ? "text" : "password"} value={pw2} onChange={(e) => setPw2(e.target.value)} placeholder="비밀번호 확인" autoComplete="new-password" onKeyDown={(e) => e.key === "Enter" && submit()} style={inputStyle} />}
            {err && <div style={{ fontSize: 12, color: googleHint ? T.ink : T.blunder, marginBottom: 8, lineHeight: 1.5, fontWeight: googleHint ? 700 : 400 }}>{err}</div>}
            <button onClick={submit} disabled={busy} className="press" style={{ width: "100%", padding: "11px 0", borderRadius: 10, background: "linear-gradient(180deg,#3A2516,#241509)", color: T.ivoryHi, fontWeight: 800, border: "none", cursor: "pointer", marginBottom: 10 }}>{busy ? "처리 중…" : (mode === "login" ? "로그인" : "가입하고 시작")}</button>
            <div style={{ display: "flex", alignItems: "center", gap: 8, margin: "2px 0 10px" }}><div style={{ flex: 1, height: 1, background: "#C9B58C" }} /><span style={{ fontSize: 11, color: T.inkSoft }}>또는</span><div style={{ flex: 1, height: 1, background: "#C9B58C" }} /></div>
            <button onClick={authGoogleStart} className="press" style={{ width: "100%", padding: "10px 0", borderRadius: 10, background: "#fff", color: "#3c4043", fontWeight: 700, border: "1px solid #CDB98E", cursor: "pointer", marginBottom: 10, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}><GoogleG /> Google로 계속하기</button>
            {mode === "login" && <div style={{ textAlign: "center", marginBottom: 8 }}><button onClick={() => { setMode("reset"); setErr(""); setSent(false); setPw(""); }} style={{ color: T.inkSoft, fontSize: 12, background: "none", border: "none", cursor: "pointer", textDecoration: "underline" }}>비밀번호를 잊으셨나요?</button></div>}
            <div style={{ textAlign: "center", fontSize: 12.5, color: T.inkSoft }}>
              {mode === "login" ? "계정이 없나요? " : "이미 계정이 있나요? "}
              <button onClick={() => { setMode(mode === "login" ? "signup" : "login"); setErr(""); setGoogleHint(false); setPw2(""); }} style={{ color: "#5A3A22", fontWeight: 800, background: "none", border: "none", cursor: "pointer", textDecoration: "underline" }}>{mode === "login" ? "회원가입" : "로그인"}</button>
            </div>
            <p style={{ fontSize: 10.5, color: T.inkSoft, marginTop: 10, lineHeight: 1.4 }}>이메일·비밀번호로 가입합니다. 아이디는 친구 검색·프로필에 공개로 표시되며, 진도(도감·해결한 퍼즐)는 계정에 저장됩니다.</p>
          </>
        )}
      </div>
    </div>
  );
}

function NewPasswordModal({ recovery, onDone, onClose }) {
  const [pw, setPw] = useState(""); const [pw2, setPw2] = useState("");
  const [err, setErr] = useState(""); const [busy, setBusy] = useState(false);
  const submit = async () => {
    setErr("");
    if (pw.length < 6) { setErr("비밀번호는 6자 이상이어야 합니다."); return; }
    if (pw !== pw2) { setErr("비밀번호가 일치하지 않습니다."); return; }
    setBusy(true);
    try { const r = await authSetPassword(recovery, pw); if (!r.ok) { setErr("재설정에 실패했습니다. 링크가 만료되었을 수 있습니다."); setBusy(false); return; } onDone(r.account || null); }
    catch { setErr("처리 중 오류가 발생했습니다."); setBusy(false); }
  };
  const inputStyle = { width: "100%", padding: "10px 12px", borderRadius: 9, border: "1px solid #C9B58C", marginBottom: 8, background: "#fff", color: T.ink };
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.6)", zIndex: 90, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
      <div style={{ width: "100%", maxWidth: 340, background: "linear-gradient(180deg,#F2E8D5,#E2D2B2)", borderRadius: 16, padding: 20, border: "1px solid #CDB98E", boxShadow: "0 20px 50px -10px rgba(0,0,0,.7)" }}>
        <div className="flex items-center justify-between" style={{ marginBottom: 14 }}>
          <div style={{ fontSize: 17, fontWeight: 800, color: T.ink }}>새 비밀번호 설정</div>
          <button onClick={onClose} className="press" style={{ width: 28, height: 28, borderRadius: 8, border: "none", background: "#0002", color: T.ink, cursor: "pointer" }}>✕</button>
        </div>
        <input type="password" value={pw} onChange={(e) => setPw(e.target.value)} placeholder="새 비밀번호 (6자 이상)" autoComplete="new-password" style={inputStyle} />
        <input type="password" value={pw2} onChange={(e) => setPw2(e.target.value)} placeholder="새 비밀번호 확인" autoComplete="new-password" onKeyDown={(e) => e.key === "Enter" && submit()} style={inputStyle} />
        {err && <div style={{ fontSize: 12, color: T.blunder, marginBottom: 8 }}>{err}</div>}
        <button onClick={submit} disabled={busy} className="press" style={{ width: "100%", padding: "11px 0", borderRadius: 10, background: "linear-gradient(180deg,#3A2516,#241509)", color: T.ivoryHi, fontWeight: 800, border: "none", cursor: "pointer" }}>{busy ? "설정 중…" : "비밀번호 변경하고 로그인"}</button>
      </div>
    </div>
  );
}

export default function App() {
  const [tab, setTab] = useState("learn");
  const [unlocked, setUnlocked] = useState(new Set());
  const [newUnlocks, setNewUnlocks] = useState(0);
  const [puzzles, setPuzzles] = useState([]);
  const [learnFocus, setLearnFocus] = useState(null);   // (UX4) 탭 이동에도 집중 학습 유지
  const [puzzleActive, setPuzzleActive] = useState(null);   // (UX4) 탭 이동에도 퍼즐 창 유지
  const [deletedPuzzles, setDeletedPuzzles] = useState(new Set()); // (UX5) 삭제한 퍼즐(자동 재생성 방지)
  const [solveCounts, setSolveCounts] = useState({});              // (UX6) 번호별 전역 풀이수
  const [earnedTitles, setEarnedTitles] = useState(new Set());     // (기능4) 획득 칭호(영구)
  const [currentTitle, setCurrentTitle] = useState(null);         // 장착 칭호
  const [profile, setProfile] = useState({ nickname: "", chesscom: "" });
  const [loaded, setLoaded] = useState(false);
  const [liveOn, setLiveOn] = useState(true);
  const [focusActive, setFocusActive] = useState(false);
  const [toast, setToast] = useState(null);
  const [solved, setSolved] = useState(new Set());
  const [user, setUser] = useState(null); // username (표시/검색)
  const [uid, setUid] = useState(null);    // auth uid (데이터 접근)
  const [authOpen, setAuthOpen] = useState(false);
  const [recovery, setRecovery] = useState(null);
  const [needUser, setNeedUser] = useState(null);   // 최초 구글 로그인 → 아이디 설정 대기
  const [authNotice, setAuthNotice] = useState("");   // 구글 콜백 오류 안내
  const [searchOpen, setSearchOpen] = useState(false);
  const [friendsOpen, setFriendsOpen] = useState(false);
  const [pendingFriendCount, setPendingFriendCount] = useState(0);
  // (UI8) 메인 화면 친구 버튼에 보류 중인 요청 수를 배지로 표시 — 요청 탭을 열지 않아도 보이도록
  useEffect(() => {
    if (!uid) { setPendingFriendCount(0); return; }
    let cancelled = false;
    const check = async () => {
      const e = await friendEdges();
      if (cancelled) return;
      setPendingFriendCount(e.filter((x) => x.status !== "accepted" && x.to_uid === uid).length);
    };
    check();
    const id = setInterval(check, 30000);
    return () => { cancelled = true; clearInterval(id); };
  }, [uid, friendsOpen]);
  const [authMode, setAuthMode] = useState("login");
  const [confirmLogout, setConfirmLogout] = useState(false);
  const [contentVer, setContentVer] = useState(0);
  const [navNonce, setNavNonce] = useState(0);
  const [devOn, setDevOn] = useState(false);
  const [codevOn, setCodevOn] = useState(false);   // (기능3) 공동 개발자 모드
  const [learnSans, setLearnSans] = useState([]);
  const [learnFuture, setLearnFuture] = useState([]);
  const [learnExtra, setLearnExtra] = useState({});
  const engine = useEngine();
  const chesscom = useChessCom(profile.chesscom);

  useEffect(() => { loadContent().then(() => setContentVer((v) => v + 1)); }, []);
  const bumpContent = useCallback(async () => { await saveContent(); setContentVer((v) => v + 1); }, []);
  const isDev = user === DEV_ACCOUNT;
  const isCodev = !!user && Array.isArray(CONTENT.codev) && CONTENT.codev.includes(user);
  const canEdit = (isDev && devOn) || (isCodev && codevOn);   // (기능3) 분기점 해설·수 설명·수 키워드 수정 권한
  const canAdd = canEdit;
  const canManageCodev = isDev && devOn;
  const devUnlockAll = (isDev && devOn) || (isCodev && codevOn);                       // 공동 개발자 지정/해제는 개발자만
  const openAuth = (mode) => { setAuthMode(mode); setAuthOpen(true); };
  useEffect(() => { (async () => {
    const _rec = parseRecoveryHash(); if (_rec) setRecovery(_rec);
    const _oauth = _rec ? null : parseOAuthHash();
    if (!_rec && !_oauth) { const _oerr = parseOAuthError(); if (_oerr) { setAuthNotice("Google 로그인을 완료하지 못했어요. 이미 다른 방식으로 가입된 이메일일 수 있습니다."); try { window.history.replaceState(null, "", window.location.pathname + window.location.search); } catch { } } }
    const raw = await store.get("chess_state_v5");
    if (raw) { try { const d = JSON.parse(raw); setUnlocked(new Set(d.unlocked || [])); setProfile(d.profile || { nickname: "", chesscom: "" }); setPuzzles(d.puzzles || []); setSolved(new Set(d.solved || [])); setDeletedPuzzles(new Set(d.deleted || [])); setEarnedTitles(new Set(d.titles || [])); if (d.currentTitle) setCurrentTitle(d.currentTitle); if (Array.isArray(d.learnSans)) setLearnSans(d.learnSans); if (d.learnExtra) setLearnExtra(d.learnExtra); } catch { } }
    try { if (!_rec && !_oauth) { const acc = await authRestore(); if (acc) { setUser(acc.username); setUid(acc.uid); const pr = acc.progress || {}; if (pr.unlocked) setUnlocked(new Set(pr.unlocked)); if (pr.puzzles) setPuzzles(pr.puzzles); if (pr.solved) setSolved(new Set(pr.solved)); if (pr.deleted) setDeletedPuzzles(new Set(pr.deleted)); if (pr.titles) setEarnedTitles(new Set(pr.titles)); if (pr.currentTitle) setCurrentTitle(pr.currentTitle); const pub = acc.pub || {}; if (pub.chesscom || pub.nickname) setProfile((p) => ({ ...p, chesscom: pub.chesscom || p.chesscom, nickname: pub.nickname || p.nickname })); } } } catch { }
    if (_oauth) { try { const acc = await authFromHash(_oauth); try { window.history.replaceState(null, "", window.location.pathname + window.location.search); } catch { } if (acc) { if (acc.username) onAuth(acc); else setNeedUser(acc); } } catch { } }
    try { const counts = await puzzleSolveCounts(); if (counts && Object.keys(counts).length) setSolveCounts(counts); } catch { }
    setLoaded(true);
  })(); }, []);
  useEffect(() => { if (loaded && uid && user) publishProfile(uid, user, { nickname: profile.nickname || "", photo: profile.photo || "", chesscom: profile.chesscom || "", title: currentTitle || "" }); }, [loaded, uid, user, profile.nickname, profile.photo, profile.chesscom, currentTitle]);
  useEffect(() => { if (loaded) store.set("chess_state_v5", JSON.stringify({ unlocked: [...unlocked], profile, puzzles, solved: [...solved], deleted: [...deletedPuzzles], titles: [...earnedTitles], currentTitle, liveOn, learnSans, learnExtra })); }, [unlocked, profile, puzzles, solved, deletedPuzzles, earnedTitles, currentTitle, liveOn, loaded, learnSans, learnExtra]);
  useEffect(() => { if (loaded && uid) progressSave(uid, { unlocked: [...unlocked], puzzles, solved: [...solved], deleted: [...deletedPuzzles], titles: [...earnedTitles], currentTitle }); }, [unlocked, puzzles, solved, deletedPuzzles, earnedTitles, currentTitle, uid, loaded]);
  // (기능4) 해결 횟수로부터 새 칭호 획득 → 영구 저장 + 획득 알림(장착 버튼)
  const titleCounts = useMemo(() => familyCounts(puzzles, solved), [puzzles, solved]);
  useEffect(() => {
    if (!loaded) return;
    const newly = [...achievableTitles(titleCounts)].filter((id) => !earnedTitles.has(id));
    if (!newly.length) return;
    setEarnedTitles((prev) => { const n = new Set(prev); newly.forEach((id) => n.add(id)); return n; });
    const order = TITLE_TIERS.map((t) => t.rank);
    const top = newly.slice().sort((a, b) => order.indexOf(b.split(":")[1]) - order.indexOf(a.split(":")[1]))[0];
    setToast({ type: "title", id: top }); setTimeout(() => setToast((t) => (t && t.type === "title" ? null : t)), 6000);
  }, [titleCounts, loaded]);
  const equipTitle = useCallback((id) => { setCurrentTitle(id); setToast((t) => (t && t.type === "title" ? null : t)); }, []);

  const onAuth = useCallback((acc) => { if (!acc) return; setUser(acc.username); setUid(acc.uid); const pr = acc.progress || {}; if (pr.unlocked) setUnlocked(new Set(pr.unlocked)); if (pr.puzzles) setPuzzles(pr.puzzles); if (pr.solved) setSolved(new Set(pr.solved)); if (pr.deleted) setDeletedPuzzles(new Set(pr.deleted)); if (pr.titles) setEarnedTitles(new Set(pr.titles)); if (pr.currentTitle) setCurrentTitle(pr.currentTitle); const pub = acc.pub || {}; if (pub.chesscom || pub.nickname) setProfile((p) => ({ ...p, chesscom: pub.chesscom || p.chesscom, nickname: pub.nickname || p.nickname })); setAuthOpen(false); }, []);
  const logout = useCallback(() => { authLogout(); setUser(null); setUid(null); setDevOn(false); setConfirmLogout(false); }, []);
  const unlockOpening = useCallback((keyStr) => { let isNew = false; setUnlocked((p) => { if (p.has(keyStr)) return p; isNew = true; const n = new Set(p); const parts = keyStr.split(" ").filter(Boolean); for (let i = 1; i <= parts.length; i++) n.add(parts.slice(0, i).join(" ")); return n; }); if (isNew) setNewUnlocks((n) => n + 1); return isNew; }, []);
  const onLearned = useCallback((name) => { setToast({ name }); setTimeout(() => setToast(null), 2600); }, []);
  const onSavePuzzle = useCallback((pz) => { if (deletedPuzzles.has(pz.id) && !solved.has(pz.id)) return; if (!isPuzzleSequenceValid(pz)) { console.warn("퍼즐 저장 거부(불법 수순):", pz.id); return; } setPuzzles((prev) => { if (prev.some((x) => x.id === pz.id)) return prev; puzzleShare(pz); return [...prev, pz]; }); }, [deletedPuzzles, solved]);
  const onDeletePuzzle = useCallback((id) => { setPuzzles((prev) => prev.filter((x) => x.id !== id)); setDeletedPuzzles((p) => { const n = new Set(p); n.add(id); return n; }); }, []);
  const onSolved = useCallback((id) => { const already = solved.has(id); if (!already) setSolved((p) => { const n = new Set(p); n.add(id); return n; }); if (user && !already) { const no = puzzleNo(id); puzzleSolveInc(no).then((c) => { if (c != null) setSolveCounts((m) => ({ ...m, [no]: c })); }); } }, [user, solved]);
  const switchTab = (k) => { if (k === "dex") setNewUnlocks(0); setNavNonce((n) => n + 1); setTab(k); };
  const onOpenOpening = useCallback((name) => {
    const path = findOpeningPathByName(name);
    setTab("learn");
    if (!path || !path.length) return;
    const tSans = path.slice(0, -1); const tSan = path[path.length - 1];
    const pnode = snapNode(tSans); const mm = pnode && pnode.moves.find((x) => stripSuffix(x.san) === stripSuffix(tSan));
    const node2 = snapNode(path); const nm = (node2 && node2.opening) ? node2.opening.name : name;
    setLearnSans(tSans);
    setLearnFocus({ sans: tSans, san: tSan, m: mm || { san: tSan }, ply: tSans.length, isNew: false, name: nm });
  }, []);
  const onOpenPuzzle = useCallback(async (pzId, fallback) => {
    setTab("puzzle");
    let pz = await puzzleFetch(puzzleNo(pzId));   // (기능2) 서버(전역)에서 조회 — 생성자 무관
    if (!pz) pz = fallback || null;               // 서버에 아직 없으면 방금 만든 것
    if (pz) setPuzzleActive(pz);
  }, []);
  useEffect(() => { if (!puzzleActive) return; setPuzzles((prev) => prev.some((x) => x.id === puzzleActive.id) ? prev : ((deletedPuzzles.has(puzzleActive.id) && !solved.has(puzzleActive.id)) ? prev : [...prev, puzzleActive])); }, [puzzleActive]);   // (UX3) 열어본 퍼즐은 로컬 탭에 추가

  return (
    <div style={{ minHeight: "100vh", background: "transparent", fontFamily: "system-ui, -apple-system, 'Noto Sans KR', sans-serif" }}>
      <style>{"button{transition:transform .08s ease, box-shadow .08s ease} button:not(:disabled):active{transform:scale(.94)} @keyframes lockpop{0%{transform:scale(.6);opacity:0}50%{transform:scale(1.1)}100%{transform:scale(1);opacity:1}}"}</style>
      <div aria-hidden="true" style={{ position: "fixed", inset: 0, zIndex: -2, background: "radial-gradient(130% 120% at 50% -10%, #34230F 0%, #150C06 65%)" }} />
      <GeoBackdrop />
      <header className="flex items-center justify-between" style={{ padding: "16px 20px", borderBottom: "1px solid #000", background: "linear-gradient(180deg,#3A2516,#2A1810)" }}>
        <div className="flex items-center gap-3">
          <Mascot name="milku" emotion="great" size={64} style={{ filter: "drop-shadow(0 2px 3px rgba(0,0,0,.5))" }} />
          <div style={{ fontWeight: 900, fontSize: 20, letterSpacing: "-.01em", background: "linear-gradient(180deg,#F3E2C0,#C49A50)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>OpenChess</div>
        </div>
        <div className="flex items-center" style={{ gap: 10 }}>
          {user ? (
            <>
              <span style={{ color: T.brassHi, fontSize: 13, fontWeight: 800, maxWidth: 96, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{user}</span>
              <button onClick={() => setConfirmLogout(true)} className="press" style={{ padding: "6px 11px", borderRadius: 8, background: T.ebony3, color: T.ivory, border: "1px solid #000", fontSize: 12, cursor: "pointer" }}>로그아웃</button>
            </>
          ) : (
            <>
              <button onClick={() => openAuth("login")} className="press" style={{ padding: "6px 12px", borderRadius: 8, background: "transparent", color: T.ivory, border: "1px solid " + T.brass, fontSize: 12.5, fontWeight: 700, cursor: "pointer" }}>로그인</button>
              <button onClick={() => openAuth("signup")} className="press" style={{ padding: "6px 12px", borderRadius: 8, background: "linear-gradient(180deg," + T.brass + ",#A8842F)", color: "#241509", border: "none", fontSize: 12.5, fontWeight: 800, cursor: "pointer" }}>회원가입</button>
            </>
          )}
          <span style={{ width: 1, height: 22, background: "linear-gradient(180deg,transparent," + T.brass + ",transparent)", opacity: .55 }} />
          <button onClick={() => setSearchOpen(true)} aria-label="유저 검색" className="press" style={{ width: 34, height: 34, borderRadius: 9, background: T.ebony3, color: T.brassHi, border: "1px solid " + T.brass, cursor: "pointer", display: "inline-flex", alignItems: "center", justifyContent: "center" }}><Search size={16} /></button>
          {user && <button onClick={() => setFriendsOpen(true)} aria-label="친구" className="press" style={{ position: "relative", width: 34, height: 34, borderRadius: 9, background: T.ebony3, color: T.brassHi, border: "1px solid " + T.brass, cursor: "pointer", display: "inline-flex", alignItems: "center", justifyContent: "center" }}>
            <Users size={16} />
            {pendingFriendCount > 0 && <span style={{ position: "absolute", top: -6, right: -6, minWidth: 16, height: 16, padding: "0 3px", borderRadius: 999, background: T.blunder, color: "#fff", fontSize: 9.5, fontWeight: 800, display: "flex", alignItems: "center", justifyContent: "center", border: "1px solid #000", lineHeight: 1 }}>{pendingFriendCount > 9 ? "9+" : pendingFriendCount}</span>}
          </button>}
        </div>
      </header>
      {authOpen && <AuthModal key={authMode} initialMode={authMode} onClose={() => setAuthOpen(false)} onAuth={onAuth} />}
      {recovery && <NewPasswordModal recovery={recovery} onDone={(acc) => { setRecovery(null); if (acc) onAuth(acc); }} onClose={() => setRecovery(null)} />}
      {authNotice && <div onClick={() => setAuthNotice("")} style={{ position: "fixed", left: "50%", bottom: 90, transform: "translateX(-50%)", zIndex: 95, maxWidth: 340, width: "calc(100% - 32px)", background: "#241509", color: "#F2E8D5", border: "1px solid #C49A50", borderRadius: 12, padding: "12px 14px", fontSize: 13, lineHeight: 1.5, boxShadow: "0 12px 30px -8px rgba(0,0,0,.6)", cursor: "pointer" }}>{authNotice} <span style={{ opacity: .7, fontSize: 11 }}>(탭하여 닫기)</span></div>}
      {needUser && <UsernameSetupModal account={needUser} onDone={(acc) => { setNeedUser(null); if (acc) onAuth(acc); }} onCancel={async () => { try { await authLogout(); } catch { } setNeedUser(null); setUser(null); setUid(null); }} />}
      {searchOpen && <UserSearchModal me={user} onClose={() => setSearchOpen(false)} />}
      {friendsOpen && <FriendsModal me={user} myUid={uid} onClose={() => setFriendsOpen(false)} />}
      {confirmLogout && (
        <div onClick={() => setConfirmLogout(false)} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.6)", zIndex: 85, display: "flex", alignItems: "center", justifyContent: "center", padding: 16 }}>
          <div onClick={(e) => e.stopPropagation()} style={{ maxWidth: 300, width: "100%", background: "linear-gradient(180deg,#F2E8D5,#E2D2B2)", borderRadius: 14, padding: 20, border: "1px solid #CDB98E", boxShadow: "0 20px 50px -10px rgba(0,0,0,.7)" }}>
            <div style={{ fontSize: 15, fontWeight: 800, color: T.ink, marginBottom: 6 }}>로그아웃</div>
            <p style={{ fontSize: 13, color: T.inkSoft, marginBottom: 16 }}>{user} 계정에서 로그아웃할까요?</p>
            <div className="flex gap-2 justify-end">
              <button onClick={() => setConfirmLogout(false)} className="press" style={{ padding: "8px 14px", borderRadius: 9, border: "1px solid #C9B58C", background: "transparent", color: T.ink, fontWeight: 700, cursor: "pointer" }}>취소</button>
              <button onClick={logout} className="press" style={{ padding: "8px 14px", borderRadius: 9, border: "none", background: T.blunder, color: "#fff", fontWeight: 800, cursor: "pointer" }}>로그아웃</button>
            </div>
          </div>
        </div>
      )}

      {toast && (
        <div style={{ position: "fixed", top: 70, left: "50%", transform: "translateX(-50%)", zIndex: 60, animation: "lockpop .4s ease", width: "calc(100% - 32px)", maxWidth: 360 }}>
          {toast.type === "title" ? (
            <div style={{ background: "linear-gradient(180deg,#3A2516,#241509)", color: T.ivoryHi, padding: 14, borderRadius: 14, border: "1px solid " + T.brass, boxShadow: "0 10px 30px -8px rgba(0,0,0,.7)" }}>
              <div className="flex items-center gap-2" style={{ marginBottom: 10 }}><Mascot name="kokoa" emotion="celebrate" size={58} /><div style={{ fontWeight: 800, fontSize: 13.5, color: T.brassHi }}>새로운 칭호 획득!</div></div>
              <TitleBadge id={toast.id} earned equipped={currentTitle === toast.id} onEquip={equipTitle} />
            </div>
          ) : (
            <div className="flex items-center gap-2" style={{ background: "linear-gradient(180deg,#3A2516,#241509)", color: T.ivoryHi, padding: "12px 18px", borderRadius: 12, border: "1px solid " + T.brass, boxShadow: "0 10px 30px -8px rgba(0,0,0,.7)" }}>
              <Mascot name="kokoa" emotion="celebrate" size={62} />
              <div><div style={{ fontWeight: 800, fontSize: 13, color: T.brassHi }}>새로운 오프닝 잠금 해제!</div><div style={{ fontSize: 12 }}>{toast.name}</div></div>
            </div>
          )}
        </div>
      )}

      <main style={{ maxWidth: 1080, margin: "0 auto", padding: "22px 18px 110px" }}>
        {tab === "learn" && <LearnTab engine={engine} liveOn={liveOn} onFocusActive={setFocusActive} unlockOpening={unlockOpening} onLearned={onLearned} chesscom={chesscom} onSavePuzzle={onSavePuzzle} contentVer={contentVer} canEdit={canEdit} canAdd={canAdd} bumpContent={bumpContent} sans={learnSans} setSans={setLearnSans} future={learnFuture} setFuture={setLearnFuture} extra={learnExtra} setExtra={setLearnExtra} focus={learnFocus} setFocus={setLearnFocus} puzzles={puzzles} onOpenPuzzle={onOpenPuzzle} onOpenFocusBranch={setTab} />}
        {tab === "dex" && <CollectionTab key={"dex-" + navNonce} unlocked={unlocked} unlockAll={devUnlockAll} liveOn={liveOn} contentVer={contentVer} chesscom={chesscom} earnedTitles={devUnlockAll ? new Set(ALL_TITLE_IDS) : earnedTitles} titleCounts={titleCounts} currentTitle={currentTitle} onEquipTitle={equipTitle} />}
        {tab === "puzzle" && <PuzzleTab puzzles={puzzles} solved={solved} onSolved={onSolved} onDeletePuzzle={onDeletePuzzle} solveCounts={solveCounts} active={puzzleActive} setActive={setPuzzleActive} />}
        {tab === "set" && <SettingsTab key={"set-" + navNonce} profile={profile} setProfile={setProfile} engineStatus={engine.status} liveOn={liveOn} setLiveOn={setLiveOn} chesscomStatus={chesscom.status} chesscom={chesscom} user={user} isDev={isDev} isCodev={isCodev} devOn={devOn} setDevOn={setDevOn} codevOn={codevOn} setCodevOn={setCodevOn} canManageCodev={canManageCodev} canAdd={canAdd} canEdit={canEdit} bumpContent={bumpContent} contentVer={contentVer} openAuth={openAuth} earnedTitles={earnedTitles} currentTitle={currentTitle} onEquipTitle={equipTitle} onOpenOpening={onOpenOpening} />}
      </main>

      <nav style={{ position: "fixed", left: 0, right: 0, bottom: 0, background: "linear-gradient(180deg,#2E1B10,#160C06)", borderTop: "1px solid #000", height: 66, paddingBottom: "env(safe-area-inset-bottom)" }}>
        {(
          <div className="flex" style={{ justifyContent: "center", margin: "0 auto", height: "100%", gap: 34, padding: "0 18px" }}>
            {TABS.map(({ key, label, Icon }) => { const on = tab === key; const badge = key === "dex" ? newUnlocks : 0; return (
              <button key={key} onClick={() => switchTab(key)} className="flex flex-col items-center justify-center gap-1" style={{ width: 60, color: on ? T.brassHi : "#8A7458", position: "relative", background: "none", border: "none", cursor: "pointer" }}>
                {on && <span style={{ position: "absolute", top: 0, height: 3, width: 34, borderRadius: 3, background: T.brass }} />}
                <span style={{ position: "relative" }}><Icon size={21} />{badge > 0 && <span style={{ position: "absolute", top: -5, right: -8, minWidth: 16, height: 16, padding: "0 4px", borderRadius: 8, background: "#D33", color: "#fff", fontSize: 10, fontWeight: 800, display: "flex", alignItems: "center", justifyContent: "center" }}>{badge}</span>}</span>
                <span style={{ fontSize: 11.5, fontWeight: on ? 700 : 500 }}>{label}</span>
              </button>); })}
          </div>
        )}
      </nav>
    </div>
  );
}
